// Pick two operators (as 3x3 rotation matrices)
const angle = (deg) => deg * Math.PI / 180;

// HARM: rotate around X-axis by 60°
const a = angle(60);
const HARM = [
  [1, 0, 0],
  [0, Math.cos(a), -Math.sin(a)],
  [0, Math.sin(a), Math.cos(a)]
];

// HEAL: rotate around Y-axis by 45°
const b = angle(45);
const HEAL = [
  [Math.cos(b), 0, Math.sin(b)],
  [0, 1, 0],
  [-Math.sin(b), 0, Math.cos(b)]
];

// Matrix multiply
function mm(A, B) {
  return A.map((row, i) =>
    B[0].map((_, j) =>
      row.reduce((s, _, k) => s + A[i][k] * B[k][j], 0)
    )
  );
}

// Matrix subtract
function ms(A, B) {
  return A.map((row, i) => row.map((v, j) => v - B[i][j]));
}

const AB = mm(HARM, HEAL);
const BA = mm(HEAL, HARM);
const comm = ms(AB, BA);

// Frobenius norm of commutator
const norm = Math.sqrt(
  comm.flat().reduce((s, v) => s + v * v, 0)
).toFixed(4);

return `[HARM, HEAL] commutator norm: ${norm}\n` +
  `(0 = commutes perfectly, >0 = order matters)\n\n` +
  `Commutator matrix:\n` +
  comm.map(r => r.map(v => v.toFixed(3)).join('  ')).join('\n') +
  `\n\n→ Try changing the angles to see how\n  non-commutativity changes!`;

// Compare RotatE (diagonal) vs full SO(3) rotation
const a = Math.PI / 4; // 45 degrees

// RotatE: independent rotations per dimension
const rotatE = [
  [Math.cos(a), 0, 0],
  [0, Math.cos(2*a), 0],
  [0, 0, Math.cos(3*a)]
];

// Full SO(3): coupled rotation (around axis [1,1,1]/√3)
const c = Math.cos(a), s = Math.sin(a);
const fullSO3 = [
  [(2*c+1)/3, (1-c-s*Math.sqrt(3))/3, (1-c+s*Math.sqrt(3))/3],
  [(1-c+s*Math.sqrt(3))/3, (2*c+1)/3, (1-c-s*Math.sqrt(3))/3],
  [(1-c-s*Math.sqrt(3))/3, (1-c+s*Math.sqrt(3))/3, (2*c+1)/3]
];

// Entity vector
const entity = [0.8, 0.3, 0.5];

function apply(M, v) {
  return M.map(row => row.reduce((s, m, i) => s + m * v[i], 0));
}

const r1 = apply(rotatE, entity);
const r2 = apply(fullSO3, entity);

return `Entity:   [${entity.map(v=>v.toFixed(2)).join(', ')}]\n` +
  `RotatE:   [${r1.map(v=>v.toFixed(3)).join(', ')}]\n` +
  `Full SO3: [${r2.map(v=>v.toFixed(3)).join(', ')}]\n\n` +
  `Key difference: RotatE transforms each\n` +
  `dimension independently. Full SO(3) couples\n` +
  `them — dimension 1 affects dimension 2.\n\n` +
  `This coupling is HOW operators encode that\n` +
  `harming someone's body also affects their\n` +
  `emotional state.`;

// Simulate adjoint action: how HARM modifies HEAL over time
const steps = 8;
const epsilon = 0.15; // strength of adjoint action

// Represent operators as 2D vectors in 'operator space'
// (massive simplification of the real Lie algebra)
let heal = { effectiveness: 1.0, caution: 0.0 };
const harm_adjoint = { effectiveness: -0.3, caution: 0.7 };

let trajectory = [`t=0: eff=${heal.effectiveness.toFixed(2)}, ` +
  `caut=${heal.caution.toFixed(2)} — naive healer`];

for (let t = 1; t <= steps; t++) {
  heal.effectiveness += epsilon * harm_adjoint.effectiveness;
  heal.caution += epsilon * harm_adjoint.caution;

  let label = '';
  if (heal.caution > 0.8) label = ' — burned out';
  else if (heal.caution > 0.5) label = ' — cautious expert';
  else if (heal.caution > 0.2) label = ' — learning boundaries';

  trajectory.push(
    `t=${t}: eff=${heal.effectiveness.toFixed(2)}, ` +
    `caut=${heal.caution.toFixed(2)}${label}`
  );
}

return `How repeated HARM modifies the HEAL operator:\n` +
  `(via adjoint action ad(HARM)(HEAL))\n\n` +
  trajectory.join('\n') +
  `\n\n→ The operator itself evolves!\n` +
  `  This IS character development.`;

