import torch
import torch.nn as nn

class LieAlgebraOperator(nn.Module):
    def __init__(self, dim, num_operators):
        super().__init__()
        # Learn antisymmetric matrices (upper triangular, then skew-symmetrize)
        self.upper = nn.Parameter(
            torch.randn(num_operators, dim, dim) * 0.01
        )

    def get_algebra_element(self, op_idx):
        """Get antisymmetric matrix (Lie algebra element)"""
        U = self.upper[op_idx]
        return U - U.T  # Skew-symmetrize

    def get_group_element(self, op_idx):
        """Get rotation matrix via matrix exponential"""
        return torch.matrix_exp(self.get_algebra_element(op_idx))

    def commutator(self, i, j):
        """Compute [op_i, op_j] in the Lie algebra"""
        A = self.get_algebra_element(i)
        B = self.get_algebra_element(j)
        return A @ B - B @ A  # Also antisymmetric!

    def apply(self, op_idx, entity_embedding):
        """Apply operator to entity"""
        R = self.get_group_element(op_idx)
        return R @ entity_embedding
